                            <label>Start Date/Time</label>
                            <input type="datetime-local" name="startDateTime" value={newEvent.startDateTime} onChange={(e) => handleNewEventFieldChange('startDateTime', e.target.value)} className="form-input" />
                        </div>
                        <div className="datetime-group">
                            <label>End Date/Time</label>
                            <input type="datetime-local" name="endDateTime" value={newEvent.endDateTime} onChange={(e) => handleNewEventFieldChange('endDateTime', e.target.value)} className="form-input" />
                        </div>
                    </div>

                    <div className="form-row">
                        <div className="form-group">
                            <label>Track Positions</label>
                            <input type="text" name="trackPositions" value={newEvent.trackPositions} onChange={(e) => handleNewEventFieldChange('trackPositions', e.target.value)} placeholder="e.g., 13.0N 121.2E → 13.8N 122.1E" className="form-input" />
                        </div>
                        <div className="form-group">
                            <label>Intensity</label>
                            <input type="text" name="intensity" value={newEvent.intensity} onChange={(e) => handleNewEventFieldChange('intensity', e.target.value)} placeholder="e.g., 95 kph / 52 kt" className="form-input" />
                        </div>
                    </div>

                    <div className="form-row">
                        <div className="form-group">
                            <label>🌤️ General Weather</label>
                            <input type="text" name="general_weather" value={newEvent.general_weather} onChange={(e) => handleNewEventFieldChange('general_weather', e.target.value)} placeholder="e.g., Rainy with strong winds" className="form-input" />
                        </div>
                        <div className="form-group">
                            <label>Report Link</label>
                            <input type="url" name="reportLink" value={newEvent.reportLink} onChange={(e) => handleNewEventFieldChange('reportLink', e.target.value)} placeholder="https://..." className="form-input" />
                        </div>
                    </div>

                    <div className="form-section">
                        <h4 className="form-section-title">📊 Damage & Impact</h4>
                        <div className="form-row">
                            <div className="form-group">
                                <label>Related Incidents</label>
                                <input type="number" name="related_incidents" value={newEvent.related_incidents} placeholder="0" onChange={(e) => handleNewEventFieldChange('related_incidents', e.target.value === '' ? 0 : parseInt(e.target.value, 10))} className="form-input" />
                            </div>
                            <div className="form-group">
                                <label>Incident Remarks</label>
                                <input type="text" name="remark_related_incidents" value={newEvent.remark_related_incidents} placeholder="Remarks..." onChange={(e) => handleNewEventFieldChange('remark_related_incidents', e.target.value)} className="form-input" />
