                                <input type="text" name="remark_casualties" value={newEvent.remark_casualties} placeholder="Remarks..." onChange={(e) => handleNewEventFieldChange('remark_casualties', e.target.value)} className="form-input" />
                            </div>
                        </div>

                        <div className="form-row">
                            <div className="form-group">
                                <label>Power Status</label>
                                <input type="text" name="power_status" value={newEvent.power_status} placeholder="e.g., Stable, Intermittent" className="form-input" onChange={(e) => handleNewEventFieldChange('power_status', e.target.value)} />
                            </div>
                            <div className="form-group">
                                <label>Power Remarks</label>
                                <input type="text" name="remark_power_status" value={newEvent.remark_power_status} placeholder="Remarks..." className="form-input" onChange={(e) => handleNewEventFieldChange('remark_power_status', e.target.value)} />
                            </div>
