                        <div className="form-row">
                            <div className="form-group">
                                <label>Communication Lines</label>
                                <input type="text" name="communication_lines" value={newEvent.communication_lines} placeholder="e.g., Operational, Down" className="form-input" onChange={(e) => handleNewEventFieldChange('communication_lines', e.target.value)} />
                            </div>
                            <div className="form-group">
                                <label>Communication Remarks</label>
                                <input type="text" name="remark_communication_lines" value={newEvent.remark_communication_lines} placeholder="Remarks..." className="form-input" onChange={(e) => handleNewEventFieldChange('remark_communication_lines', e.target.value)} />
                            </div>
                        </div>

                        <div className="form-row">
                            <div className="form-group">
                                <label>Damage to Facilities</label>
                                <input type="text" name="damage_facilities" value={newEvent.damage_facilities} placeholder="e.g., None, Flooded" className="form-input" onChange={(e) => handleNewEventFieldChange('damage_facilities', e.target.value)} />
                            </div>
                            <div className="form-group">
                                <label>Damage Remarks</label>
                                <input type="text" name="remark_damage_facilities" value={newEvent.remark_damage_facilities} placeholder="Remarks..." className="form-input" onChange={(e) => handleNewEventFieldChange('remark_damage_facilities', e.target.value)} />
                            </div>
