                                <label>Assistance Provided</label>
                                <input type="text" name="assistance_provided" value={newEvent.assistance_provided} placeholder="e.g., None, Relief Packs Distributed" className="form-input" onChange={(e) => handleNewEventFieldChange('assistance_provided', e.target.value)} />
                            </div>
                            <div className="form-group">
                                <label>Assistance Remarks</label>
                                <input type="text" name="remark_assistance_provided" value={newEvent.remark_assistance_provided} placeholder="Remarks..." className="form-input" onChange={(e) => handleNewEventFieldChange('remark_assistance_provided', e.target.value)} />
                            </div>
                        </div>
                    </div>

                    <div className="modal-footer">
                        <button type="button" className="cancel-btn" onClick={() => { setShowAddModal(false); setIsEditingEvent(false); }}>Cancel</button>
                        <button type="submit" className="submit-btn success">{isEditingEvent ? 'Save Changes' : 'Create Event'}</button>
                    </div>
                </form>
            </div>
        </div>
    );

    // ======================== MAIN JSX RENDERING ========================
    return (
        <div className="dashboard-container" ref={mainContentRef} onScroll={handleScroll}>
            {/* Left Sidebar Menu */}
            <div className="sidebar">
                <div className="sidebar-brand">DOST R1 DRRM</div>
                <button type="button" className={`sidebar-link ${activeMenu === 'dashboard' ? 'active' : ''}`} onClick={() => setActiveMenu('dashboard')}>📊 Dashboard</button>
                <button type="button" className={`sidebar-link ${activeMenu === 'events' ? 'active' : ''}`} onClick={() => setActiveMenu('events')}>🌪️ Cyclone Events</button>
                <button type="button" className="sidebar-logout" onClick={onLogout}>🚪 Logout</button>
            </div>

            {/* Main Content Pane */}
            <div className="main-content">
                {activeMenu === 'dashboard' ? (
                    <>
                        <div className="dashboard-header">
                            <h1>Disaster Risk Reduction Management Information System</h1>
                            <div className="user-profile-badge">Welcome, {currentUser?.name || 'User'} ({currentUser?.office || 'Regional Office'})</div>
                        </div>
                        {editMode && <div className="edit-banner-alert">⚠️ You are editing situational parameters for {selectedOffice}</div>}

                        {/* Custom Core Elements */}
                        {Object.keys(officesData).length > 0 && <DashboardContent />}
                    </>
                ) : (
                    <div className="events-management-pane">
                        <div className="pane-header">
                            <h2>Cyclone Monitoring List</h2>
                            {canEditEvents && <button type="button" className="add-mun-btn" onClick={openReportModal}>+ Register Cyclone Event</button>}
                        </div>
                        <div className="events-search-bar">
                            <input type="text" placeholder="Search parameters..." value={searchTerm} onChange={handleSearchChange} className="search-input" />
                        </div>
                        <div className="events-table-wrapper">
                            <table className="damage-table">
                                <thead>
                                    <tr>
                                        <th>Event Designation</th>
                                        <th>Category</th>
                                        <th>Alert Status</th>
                                        <th>Date Reported</th>
                                        <th>Operational Actions</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {filteredEvents.map(event => (
                                        <tr key={event.id}>
                                            <td><strong>{event.name}</strong></td>
                                            <td>{event.category || 'Tropical Cyclone'}</td>
                                            <td><span className="status-badge" style={{ backgroundColor: getEventStatusLabel(event) === 'Active' ? '#28a745' : '#6c757d', color: '#fff' }}>{getEventStatusLabel(event)}</span></td>
                                            <td>{event.date}</td>
                                            <td>
                                                <button type="button" className="view-btn" onClick={() => handleEditEvent(event)}>✏️ Modify</button>
                                                {canDeployEvents && event.deployment !== 'Deployed' && event.status === 'approved' && (
                                                    <button type="button" className="add-mun-btn" style={{ marginLeft: '6px' }} onClick={() => handleNewEventFieldChange(event.id)}>🚀 Deploy</button>
                                                )}
                                                <button type="button" className="danger" style={{ marginLeft: '6px' }} onClick={() => handleDeleteEvent(event.id)}>🗑️ Remove</button>
                                            </td>
                                        </tr>
                                    ))}
                                    {filteredEvents.length === 0 && (
                                        <tr>
                                            <td colSpan="5" className="no-items">No active data matches the query definitions.</td>
                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}
            </div>

            {/* Render Context Modals dynamically */}
            {showAddModal && <AddEventModal />}
            {showImageModal && (
                <div className="modal-overlay" onClick={closeImageModal}>
                    <div className="modal-content visual-preview-modal" onClick={e => e.stopPropagation()}>
                        <button type="button" className="modal-close" onClick={closeImageModal}>×</button>
                        <img src={imageModalSrc} alt="High resolution impact context" className="modal-enlarged-image" />
                    </div>
                </div>
            )}
        </div>
    );
};

export default Dashboard;
